#include<bits/stdc++.h>
using namespace std;
long long n,a[500005],vis[500005],ans,mid,pp,x,y;
void gb(long long l,long long r)
{
	mid=(l+r)/2;
	pp=l;x=l;
	y=mid+1;
	while(x<=mid and y<=r)
	{
		if(a[x]<=a[y])	vis[pp++]=a[x++];
		else
		{
			vis[pp++]=a[y++];
			ans+=mid-x+1;
		}
	}
	while(x<=mid)
	{
		vis[pp++]=a[x++];
	}
	while(y<=r)
	{
		vis[pp++]=a[y++];
	}
	for(long long i=l;i<=r;i++)
	{
		a[i]=vis[i];
	}
}
void gbsort(long long l,long long r)
{
	if(l==r)	return;
	long long mmid=(r+l)/2;
	gbsort(l,mmid);	
	gbsort(mmid+1,r);
	gb(l,r);
}
int main()
{
	cin>>n;
	for(long long i=1;i<=n;i++)	cin>>a[i];
	gbsort(1,n);
	cout<<ans;
	return 0;
}
